{
  "provider": "binance",
  "data": {
    "displayName": "Binance",
    "logo": "https://cdn.app.com/exchanges/binance.png",
    "type": "cex",
    "credentials": [
      {
        "id": "apiKey",
        "label": "API Key",
        "required": true,
        "inputType": "text",
        "placeholder": "Enter your Binance API key",
        "minLength": 16
      },
      {
        "id": "apiSecret",
        "label": "API Secret",
        "required": true,
        "inputType": "password",
        "placeholder": "Enter your Binance API secret"
      }
    ],
    "permissions_required": ["read"],
    "instructionsUrl": "https://www.binance.com/en/support/faq/...",
    "notes": "Make sure your API key has 'read' access enabled."
  }
}

